            String completeTxnQuery = "UPDATE transactions SET status = 'COMPLETED' WHERE transaction_id = ?";
            PreparedStatement completeTxnStmt = connection.prepareStatement(completeTxnQuery);
            completeTxnStmt.setString(1, transactionId);
            completeTxnStmt.executeUpdate();
